class Product {
    int id;
    String name;
    int stock;
    double price;

    // Primary constructor with validation
    public Product(int id, String name, int stock, double price) {
        if (id <= 0) {
            throw new IllegalArgumentException("ID must be positive, got: " + id);
        }
        if (name == null || name.isBlank()) {
            throw new IllegalArgumentException("Name cannot be empty");
        }
        if (stock < 0) {
            throw new IllegalArgumentException("Stock cannot be negative, got: " + stock);
        }
        if (price < 0) {
            throw new IllegalArgumentException("Price cannot be negative, got: " + price);
        }

        this.id = id;
        this.name = name;
        this.stock = stock;
        this.price = price;
    }

    // Convenience constructor — stock defaults to 0
    public Product(int id, String name, double price) {
        this(id, name, 0, price);
    }

    public String describe() {
        return "#" + id + " " + name + " — Stock: " + stock + ", Price: ₹" + price;
    }
}

public class InventoryV2 {
    public static void main(String[] args) {
        Product[] catalog = new Product[5];
        catalog[0] = new Product(101, "Wireless Mouse", 45, 599.99);
        catalog[1] = new Product(102, "USB-C Cable", 12, 249.0);
        catalog[2] = new Product(103, "Notebook", 87, 89.5);
        catalog[3] = new Product(104, "Mechanical Keyboard", 8, 4500.0);
        catalog[4] = new Product(105, "Desk Lamp", 23, 1299.0);

        System.out.println("=== INVENTORY (V2 with Constructors) ===");
        for (Product p : catalog) {
            System.out.println(p.describe());
        }

        // Try invalid products
        try {
            Product bad = new Product(-1, "Broken", 10, 99.99);
            System.out.println("This should not print");
        } catch (IllegalArgumentException e) {
            System.out.println("\nRejected bad product: " + e.getMessage());
        }

        try {
            Product bad2 = new Product(999, "Weird", 0, -50.0);
        } catch (IllegalArgumentException e) {
            System.out.println("Rejected bad product: " + e.getMessage());
        }

        // Convenience constructor
        Product partial = new Product(106, "Out of Stock Item", 199.0);
        System.out.println("\nPartial product: " + partial.describe());
    }
}

